def process_graph(graph_data):
    # Create a copy of the graph to avoid modifying the input
    graph_copy = graph_data.copy()

    # Find the EK_AGG_BLOCK node with the specified name
    agg_node_id = None
    for n, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a3.m3' and 'EK_AGG_BLOCK' in attrs.get('type', []):
            agg_node_id = n
            break

    ranked_children = []

    if agg_node_id is not None:
        # Iterate over direct children contained by the agg block
        for _, child_id, edge_attrs in graph_copy.out_edges(agg_node_id, data=True):
            if 'RK_CONTAINS' in edge_attrs.get('type', []):
                child_attrs = graph_copy.nodes[child_id]
                # Consider only PACKET_SWITCH children (as per hierarchy)
                if 'EK_PACKET_SWITCH' in child_attrs.get('type', []):
                    total_capacity = 0
                    # Sum physical_capacity_bps of all descendant PORT nodes
                    for desc_id in nx.descendants(graph_copy, child_id):
                        desc_attrs = graph_copy.nodes[desc_id]
                        if 'EK_PORT' in desc_attrs.get('type', []):
                            total_capacity += desc_attrs.get('physical_capacity_bps', 0)
                    ranked_children.append((child_attrs.get('name', ''), total_capacity))

    # Sort by total capacity in descending order
    ranked_children.sort(key=lambda x: x[1], reverse=True)

    # Prepare the graph JSON representation
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    # Build the return object
    return_object = {
        'type': 'list',
        'data': ranked_children,
        'updated_graph': graph_json
    }
    return return_object

